const Q_BIOLOGY_2019_MODEL_I=[{"id": "objective>Biology>2019-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Only specially adapted micro-organisms are found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Salty water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Humid air </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Moist soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mouth cavities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Specially adapted micro-organisms, known as extremophiles, are found in extreme environments such as salty water (halophiles). These organisms have adapted to survive in high salt concentrations where most other organisms cannot.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants which can survive in extremely dry places are called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mesophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xerophytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrophytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angiosperms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants that can survive in extremely dry places are called xerophytes. These plants have adaptations such as thick cuticles, reduced leaf areas, sunken stomata and extensive root systems to minimize water loss and maximize water uptake.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of ______ for swimming in a tad-pole enables it to adapt in an aquatic habitat.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Swim bladder </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fins</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of a tail for swimming in a tadpole enables it to adapt in an aquatic habitat. The tail provides propulsion for the tadpole to move in water.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2019-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Possession of thin membrane enables a tapeworm to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fasten themselves to the wall of the host's intestine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lay numerous eggs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Absorb digested food from the host's intestine to their system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shield themselves inside the host's intestine with anti-enzymes in order to avoid being digested </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworms are parasitic flatworms that live in the intestines of their hosts. They have a thin membrane that allows them to absorb nutrients from the host's digested food. This is because they lack a digestive system of their own, so they rely on their host's digested food for nourishment.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following juices contains the enzyme ptyalin?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gastric juice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Succus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pancreatic juice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saliva</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ptyalin, also known as salivary amylase, is an enzyme that is found in saliva. It begins the process of digestion by breaking down starch and glycogen into maltose, a disaccharide.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2019-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following essential substance is contained in vegetable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chlorophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mineral Salts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon dioxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vegetables are rich in mineral salts. These are essential substances that the body needs for various functions, including maintaining the balance of body fluids, aiding in the transmission of nerve impulses, and contributing to the structure of body tissues.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2019-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Good quality food will perform the following functions in human except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Supplying energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Providing resistance against malaria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maintaining health</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sustaining growth</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Good quality food provides nutrients that the body needs to function properly, including providing energy, maintaining health, and sustaining growth. However, it does not provide resistance against specific diseases such as malaria. Resistance against diseases is primarily provided by the immune system, not directly by food.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2019-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is considered to be the first product of Photosynthesis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Energised Chlorophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydroxyl ions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first product of photosynthesis is starch. This is because the simple sugar formed is partly used by the plant and excesss of it is converted into starch immediately for storage and the starch is transported to other parts of the plant through the phloem vessels for storage.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2019-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the blood corpuscles are irregular and amoeboid in shape</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Erythrocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thrombocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes, also known as white blood cells, are the blood corpuscles that are irregular and amoeboid in shape. They have the ability to change their shape and move around, which allows them to engulf foreign particles and pathogens in the body. This is a key part of the body's immune response.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2019-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which organ removes the largest quantity of water from the blood?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lung</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intestine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kidney is the organ that removes the largest quantity of water from the blood. This is done through the process of filtration where the kidneys filter out waste products, excess substances, and water from the bloodstream. The filtered water and waste products form urine, which is excreted from the body.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2019-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of blood between the heart and all other parts of the body beside the lungs is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Double circulatory system </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pulmonary system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Single circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Systemic circulation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of blood between the heart and all other parts of the body beside the lungs is referred to as systemic circulation. This is the part of the cardiovascular system which carries oxygenated blood away from the heart to the body, and returns deoxygenated blood back to the heart.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2019-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The change in the genetic make up of an organism resulting in an inheritable characteristics which is new is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Locus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hybrid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diploid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mutation is a change in the genetic makeup of an organism that results in a new inheritable characteristic. This can occur spontaneously or be induced by environmental factors. Mutations can lead to variation within a species, which is a key driver of evolution.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organic molecule(s) present in the nucleus is/are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">DNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protein, DNA, RNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ATP and RNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RNA</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of a cell contains DNA, RNA, and proteins. DNA (Deoxyribonucleic acid) is the genetic material of the cell that contains the information used in the development and functioning of all living organisms. RNA (Ribonucleic acid) is a nucleic acid present in all living cells. Its principal role is to act as a messenger carrying instructions from DNA for controlling the synthesis of proteins. Proteins in the nucleus play various roles including DNA replication, gene expression, protein synthesis, and cell division.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2019-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Albinism is an expression of trait controlled by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Recessive genes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dominant genes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mutation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Albinism is a genetic condition where people are born without the usual pigment (color) in their bodies. Their bodies aren't able to make a normal amount of melanin, the chemical that is responsible for eye, skin, and hair color. Albinism is caused by recessive genes. A recessive gene is a gene that can be masked by a dominant gene. In order to have a trait that is expressed by a recessive gene, such as albinism, you must get the gene for that trait from both parents.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The male sex cells also called gametes are produced in the testes by a process called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gametogenesis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Implantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spermatogenesis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spermatozoa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The male sex cells, also known as sperm cells or gametes, are produced in the testes by a process called spermatogenesis. Spermatogenesis is the process by which haploid spermatozoa develop from germ cells in the seminiferous tubules of the testis. This process starts with the mitotic division of the stem cells located close to the basement membrane of the tubules. These cells are called spermatogonial stem cells.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2019-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes an example of fertilization in higher organisms</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fusion of sperm and egg nuclei</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pollen grain landing on a sticky stigma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ejaculation of the egg and pollen grain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ejaculation of sperm into the female body</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fertilization in higher organisms is described as the fusion of sperm and egg nuclei. This process results in the formation of a zygote, which is the first cell of a new individual. The other options do not accurately describe fertilization.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2019-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labeled III in the above diagram is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Root</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hyphae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizoids</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hyphae in a mushroom is a vegetative body parts made up of tiny and delicate thread containing nuclei  <br/> </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2019-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The organism above can be found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Arid land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secluded environments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aquatic habitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Moist environments</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is found in moist environment because of its adaptive features. Forests are ideal mushroom habitats because they provide the moisture, organic matter, and darkness that mushrooms need. Mushrooms can be found growing on the forest floor, on dead logs and branches, and even on living trees.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2019-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The possession of chloroplast in Euglena viridis enables it to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Store starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carry out photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reproduce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Respond to light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Euglena viridis </span> is a unicellular organism that possesses chloroplasts. Chloroplasts are organelles found in plant cells and some protists like Euglena. They absorb sunlight and use it in conjunction with water and carbon dioxide to produce food for the organism, a process known as photosynthesis. Therefore, the presence of chloroplasts in Euglena viridis enables it to carry out photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2019-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Viruses are pathogens of the following diseases except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tuberculosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Measles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Small pox </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Poliomyelitis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viruses are microscopic pathogens that cause various diseases in humans, including measles, smallpox, and poliomyelitis. However, tuberculosis is not caused by a virus. It is caused by a bacterium known as Mycobacterium tuberculosis. Therefore, tuberculosis is the correct answer as it is not caused by a virus.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2019-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The association between two organisms living together in which only one benefits from the association while the other is neither benefited nor harmed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commensalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dispersal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The association described in the question is known as commensalism. In commensalism, one organism benefits while the other is neither harmed nor benefited. This is different from predation where one organism benefits at the expense of the other, competition where both organisms may be harmed, and dispersal which refers to the movement of organisms from one place to another.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2019-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will have the least effect on the rate of change of the numbers in a population</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Food Supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disease </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Predation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mutation is the least likely to have an effect on the rate of change of the numbers in a population. Mutation refers to a change in the DNA sequence within a gene or chromosome of an organism resulting in the creation of a new character or trait not found in the parental type. While mutation can lead to new traits that may benefit or harm an organism, the rate at which mutations occur is generally slow and thus they are less likely to have an immediate impact on population numbers compared to factors like food supply, disease, and predation.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2019-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following controls all voluntary actions</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Olfactory lobes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cerebrum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hypothalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pons varolii</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebrum controls all voluntary actions. It is the largest part of the brain and is responsible for most of the brain's function. It controls functions such as thought, emotions, and problem-solving, and voluntary physical action. The olfactory lobes are responsible for the sense of smell, the hypothalamus controls body temperature, hunger, important aspects of parenting and attachment behaviors, thirst, fatigue, sleep, and circadian rhythms, and the pons varolii is involved in motor control and sensory analysis.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2019-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement describes an autonomic nervous system</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It always stimulates effectors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Activities are voluntary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It dials with external stimuli and their responses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It affects glands, cardiac muscles and smooth muscles</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The autonomic nervous system is a part of the nervous system that controls and regulates the internal organs without any conscious recognition or effort by the organism. It affects glands, cardiac muscles, and smooth muscles. It does not always stimulate effectors, its activities are not voluntary, and it does not deal with external stimuli and their responses.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2019-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The glomerular filtrate contains the following except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Urea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood Corpuscles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glucose</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The glomerular filtrate is the liquid that has passed through the glomerulus in the kidney and into the Bowman's capsule. It contains water, urea, and glucose, but not blood corpuscles. Blood corpuscles (red and white blood cells and platelets) are too large to pass through the glomerular filter.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2019-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following is not the theory of natural selection stated by Charles Darwin</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Characteristics acquired through use or disuse are transmitted offspring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Variations appear by themselves in a population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heredity variations are transmitted to offspring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Species that are the fittest for the environment contribute more offsprings to the next needs of the generation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of natural selection stated by Charles Darwin does not include the concept that characteristics acquired through use or disuse are transmitted to offspring. This is actually a part of Lamarck's theory of evolution, not Darwin's. Darwin's theory of natural selection includes the concepts that variations appear by themselves in a population, hereditary variations are transmitted to offspring, and species that are the fittest for the environment contribute more offspring to the next generation.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2019-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ecology is best defined as the study of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of an environment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The inter-relationship between living organisms and the environment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Living organisms in a particular area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The habitats and wild life</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecology is the scientific study of the interactions between organisms and their environment. This includes both the physical environment, which can be described as the sum total of local abiotic factors such as insolation (sunlight), climate, and geology, and the biotic environment, composed of other organisms.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following processes are involved during expiration in man except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The inter costal muscles relax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The thoracic activity first increases in volume </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The sternum moves inward </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ribs are moved downwards and inwards.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During expiration (exhalation), the process is mostly passive and the thoracic cavity decreases in volume. The intercostal muscles relax, the sternum moves inward, and the ribs move downwards and inwards. The decrease in volume causes an increase in pressure relative to the outside, which forces air out of the lungs.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2019-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of continuous variation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Human blood groups </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sex difference in human </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haemoglobin types </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Height in humans</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Continuous variation is variation that has no limit on the value that can occur within a population. Height in humans, for example, is a trait that can have a wide range of values (from very short to very tall) and is not limited to a few distinct possibilities, which is why it is considered a continuous variation. Other examples like blood groups, sex difference, and haemoglobin types are examples of discrete variation because they have a limited number of possible values.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2019-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following is an effect of clay soil on vegetation</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Supports luxuriant vegetation such as forest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supports scanty vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Does not support light vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Support arid vegetation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay soil is known for its poor drainage and compact nature. This makes it difficult for plant roots to penetrate and access nutrients, hence it supports scanty vegetation. The other options are incorrect because clay soil does not support luxuriant, light or arid vegetation due to its characteristics.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2019-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors is not considered in a terrestrial habitat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sunlight </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Humidity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Turbidity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Turbidity is a measure of the degree to which the water loses its transparency due to the presence of suspended particulates. It is a factor considered in aquatic habitats, not terrestrial habitats. The other factors like temperature, sunlight, and humidity are all considered in a terrestrial habitat.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2019-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of vertebrate assists in breathing alongside with the ribs?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sacral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caudal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thoracic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lumber</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The thoracic vertebrae assist in breathing alongside the ribs. The thoracic vertebrae are the only vertebrae that support ribs and have overlapping spinous processes. The other options, sacral, caudal, and lumber, are types of vertebrae but they do not assist in breathing.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2019-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is correct about Southern Guinea Savanna in Nigeria</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is the largest of all the biotic community in Nigeria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has plants species like Iroko, Opepe etc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has very low rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has no trees </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the largest of all the biotic community in Nigeria </div>", "topic": "LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA"}, {"id": "objective>Biology>2019-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an ecosystem, the organism which changes light energy into stored chemical energy is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decomposer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carnivore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an ecosystem, the organism which changes light energy into stored chemical energy is the producer. Producers, also known as autotrophs, convert light energy from the sun into chemical energy through a process called photosynthesis. Consumers, decomposers, and carnivores do not have this ability.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2019-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of use and disuse Lamarck proposed that evolution occurred because of the following except   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">There is natural selection of offspring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is great changes in the environment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organism develop specialised characters </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The characters are inheritable</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of use and disuse, Lamarck proposed that evolution occurred because organisms develop specialized characters due to changes in their environment, and these characters are inheritable. However, he did not propose that there is natural selection of offspring. Natural selection is a concept proposed by Charles Darwin, not Lamarck.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2019-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basis of growth involves the following processes except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cell reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell division</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell enlargement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell differentiation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Growth in biological terms involves cell division, cell enlargement, and cell differentiation. Cell reduction, however, is not a part of growth. Instead, it is a process that occurs during apoptosis or programmed cell death.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2019-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organs can be considered vestigial in humans but functional in other mammals</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The liver </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Appendix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rectum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stomach</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The appendix is considered a vestigial organ in humans. It is a small, tube-shaped organ that doesn't have a known purpose in humans. However, in other mammals, such as rabbits and rodents, the appendix is used to help digest cellulose in their diet.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2019-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The study which involves the inter-relationship between groups of organisms or species of organisms living together in an area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Autecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecological niche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Synecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Synecology is the study of groups of organisms or species of organisms living together in an area. It focuses on the interactions and relationships between different species within a community or ecosystem.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2019-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thunderstorm can be beneficial to plants because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adds line to the soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kills the pest that attacks crops </div>", "<div style=\"font-family:Cambria;font-size:17px;\">destroys some of the major crops </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adds nitrate to the soil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thunderstorms can cause nitrogen in the air to be converted into nitrates, a form of nitrogen that plants can absorb and use to grow. This process is known as nitrogen fixation. Therefore, thunderstorms can be beneficial to plants because they add nitrate to the soil.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2019-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A flowering plant having both the male and female flowers on the same plant is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Regular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Irregular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monoecious </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dioecious</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A plant that has both male and female flowers on the same plant is said to be monoecious. Monoecious is derived from the Greek words 'monos' meaning 'single' and 'oikos' meaning 'house'. This term is used in botany to describe a single plant that bears both male and female flowers.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}];
